'use client';

import { useState } from 'react';
import { X } from 'lucide-react';

export function DialogPreview(): React.ReactElement {
    const [open, setOpen] = useState(false);

    return (
        <div className="w-full max-w-sm">
            <button
                type="button"
                onClick={() => setOpen(true)}
                className="inline-flex items-center justify-center rounded-md font-medium bg-blue-600 text-white hover:bg-blue-700 transition-colors h-10 px-4 text-sm"
            >
                Open Dialog
            </button>
            {open && (
                <div className="fixed inset-0 z-50 flex items-center justify-center" onClick={() => setOpen(false)}>
                    <div className="fixed inset-0 bg-black/50" />
                    <div
                        className="relative z-10 w-full max-w-md rounded-lg border bg-white p-6 shadow-xl dark:bg-gray-900 dark:border-gray-700 animate-in fade-in zoom-in-95"
                        onClick={(e) => e.stopPropagation()}
                    >
                        <div className="flex items-center justify-between mb-4">
                            <h3 className="text-lg font-semibold text-gray-900 dark:text-gray-100">Confirm Action</h3>
                            <button type="button" onClick={() => setOpen(false)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300">
                                <X className="h-5 w-5" />
                            </button>
                        </div>
                        <p className="text-sm text-gray-600 dark:text-gray-400 mb-6">
                            Are you sure you want to continue? This action cannot be undone.
                        </p>
                        <div className="flex justify-end gap-2">
                            <button type="button" onClick={() => setOpen(false)} className="h-9 px-4 text-sm font-medium rounded-md border border-gray-300 text-gray-700 hover:bg-gray-50 dark:border-gray-600 dark:text-gray-300 dark:hover:bg-gray-800">
                                Cancel
                            </button>
                            <button type="button" onClick={() => setOpen(false)} className="h-9 px-4 text-sm font-medium rounded-md bg-red-600 text-white hover:bg-red-700">
                                Delete
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}
